/**
 * pipeline-spec-decode.test.ts — the greedy n-gram speculative-decode path in
 * Pipeline.generate is (a) DEFAULT OFF (byte-identical to baseline when the flag
 * is unset), (b) LOSSLESS when on (same tokens as the baseline greedy loop), and
 * (c) actually accepts drafted tokens (multi-token-per-forward) on a repetitive
 * sequence.
 *
 * The station is a deterministic ORACLE: a fixed `nextToken(history)` function
 * stands in for the real model. Its `verifyBatch` mirrors the Rust
 * `verify_batch_greedy` contract exactly (accept the longest argmax-matching
 * prefix of the draft, then always emit + commit the model's own next token).
 * `lmHead` returns a one-hot of `nextToken` so the BASELINE host loop
 * (disableNativeGenerate + argmax sampler) produces the same reference tokens.
 */

import { describe, expect, it } from 'vitest';

import { Pipeline } from '../pipeline';
import type { IStation } from '../types';

const HIDDEN_DIM = 4;
const VOCAB_SIZE = 8;

// Deterministic oracle "model": next token after `history`.
function oracleNextToken(history: readonly number[]): number {
  const last = history[history.length - 1] ?? 0;
  return (last * 3 + 1) % VOCAB_SIZE;
}

type NextTokenFn = (history: readonly number[]) => number;

interface SpecCounts {
  verifyBatch: number;
  /** verify-batch rounds that actually forwarded candidates (a DRAFTED round). */
  verifyBatchDrafted: number;
  verifyAcceptedTotal: number;
  lmHead: number;
  decodeNext: number;
}

/**
 * Oracle station. Tracks an internal `committed` history (= the station KV/pos)
 * so it can answer both the baseline host loop (embed/forward/lmHead/decodeNext)
 * and the spec loop (verifyBatch) consistently.
 */
function buildOracleStation(
  prompt: number[],
  next: NextTokenFn = oracleNextToken,
): { station: IStation; calls: SpecCounts } {
  const committed: number[] = [...prompt];
  const calls: SpecCounts = {
    verifyBatch: 0,
    verifyBatchDrafted: 0,
    verifyAcceptedTotal: 0,
    lmHead: 0,
    decodeNext: 0,
  };

  const oneHot = (token: number): Float32Array => {
    const logits = new Float32Array(VOCAB_SIZE);
    logits[token] = 10;
    return logits;
  };

  const station: IStation = {
    startLayer: 0,
    endLayer: 1,
    role: 'entry',
    maxBatchSize: 8,

    async embed({ tokens }) {
      return new Float32Array(tokens.length * HIDDEN_DIM).fill(0.1);
    },
    async forward({ residual }) {
      return { residual };
    },
    async lmHead() {
      // Baseline path: predict the model's next token for the committed history.
      calls.lmHead += 1;
      return oneHot(next(committed));
    },
    // Baseline host-orchestrated single token: commit + return next token.
    async decodeNext({ tokenId }) {
      calls.decodeNext += 1;
      committed.push(tokenId);
      return next(committed);
    },

    // Spec path: mirror Rust verify_batch_greedy exactly.
    async verifyBatch({ candidates, position }) {
      calls.verifyBatch += 1;
      // The host MUST thread the absolute KV slot of the first candidate, which
      // equals the running seq length (== this oracle's committed history) every
      // round. This is the CORRECTNESS fix: without it the fat-station reads a
      // stale self.pos and clobbers the warm prompt KV. Assert it threads through
      // and stays in lockstep with prompt + already-emitted tokens.
      if (position !== committed.length) {
        throw new Error(
          `verifyBatch position mismatch: got ${String(position)}, expected committed.length=${committed.length}`,
        );
      }
      const cand = Array.from(candidates);
      if (cand.length > 0) calls.verifyBatchDrafted += 1;
      const accepted: number[] = [];
      for (const c of cand) {
        if (c === next(committed)) {
          accepted.push(c);
          committed.push(c);
        } else {
          break;
        }
      }
      // Always emit + commit the model's own next token (correction/continuation).
      const nextToken = next(committed);
      committed.push(nextToken);
      calls.verifyAcceptedTotal += accepted.length;
      return {
        accepted,
        nextToken,
        acceptedCount: accepted.length,
        candidateCount: cand.length,
        pos: committed.length,
      };
    },

    async cobordismEmbed() {
      throw new Error('not used');
    },
    async cobordismLmHead() {
      throw new Error('not used');
    },
    async bizarroForward() {
      return null;
    },
  };

  return { station, calls };
}

const PROMPT = [3, 1, 4, 1, 5, 3, 1, 4, 1, 5];
const MAX_NEW = 32;

describe('Pipeline n-gram speculative decode', () => {
  it('is DEFAULT OFF: without specDecode it uses the baseline host loop', async () => {
    const { station, calls } = buildOracleStation([...PROMPT]);
    const pipeline = new Pipeline({
      stations: [station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      // No specDecode, no generateTokens on the station → baseline host decode.
      disableNativeGenerate: true,
    });
    const out = await pipeline.generate({
      promptTokens: new Uint32Array(PROMPT),
      maxNewTokens: MAX_NEW,
    });
    expect(out.length).toBe(PROMPT.length + MAX_NEW);
    expect(calls.verifyBatch).toBe(0); // never speculated
    expect(calls.decodeNext).toBeGreaterThan(0); // baseline per-token path
  });

  it('is LOSSLESS: specDecode output is byte-identical to the baseline, accepting > 0', async () => {
    // Baseline reference (spec OFF).
    const base = buildOracleStation([...PROMPT]);
    const basePipeline = new Pipeline({
      stations: [base.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      disableNativeGenerate: true,
    });
    const baseline = await basePipeline.generate({
      promptTokens: new Uint32Array(PROMPT),
      maxNewTokens: MAX_NEW,
    });

    // Speculative (spec ON via explicit config).
    const spec = buildOracleStation([...PROMPT]);
    const specPipeline = new Pipeline({
      stations: [spec.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      specDecode: true,
      specDecodeK: 4,
    });
    const tokensEmitted: number[] = [];
    const specOut = await specPipeline.generate({
      promptTokens: new Uint32Array(PROMPT),
      maxNewTokens: MAX_NEW,
      onToken: (e) => tokensEmitted.push(e.tokenId),
    });

    expect([...specOut]).toEqual([...baseline]);
    expect(specOut.length).toBe(PROMPT.length + MAX_NEW);
    expect(spec.calls.verifyBatch).toBeGreaterThan(0);
    // The first token is SEEDED via exactly one /decode-next (the prefill leaves
    // the station's self.logits stale, so the host owns + commits the first
    // token), then the verify-batch loop drives the rest.
    expect(spec.calls.decodeNext).toBe(1);
    // Accepted-draft tokens > 0 proves multi-token-per-forward on the repeats.
    expect(spec.calls.verifyAcceptedTotal).toBeGreaterThan(0);
    // The onToken stream matches the generated suffix exactly.
    expect(tokensEmitted).toEqual([...specOut].slice(PROMPT.length));
  });

  it('honors maxNewTokens exactly even when a draft would overshoot', async () => {
    const spec = buildOracleStation([...PROMPT]);
    const pipeline = new Pipeline({
      stations: [spec.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      specDecode: true,
      specDecodeK: 8,
    });
    for (const maxNew of [1, 2, 3, 7, 13]) {
      const fresh = buildOracleStation([...PROMPT]);
      const p = new Pipeline({
        stations: [fresh.station],
        hiddenDim: HIDDEN_DIM,
        vocabSize: VOCAB_SIZE,
        specDecode: true,
        specDecodeK: 8,
      });
      const out = await p.generate({
        promptTokens: new Uint32Array(PROMPT),
        maxNewTokens: maxNew,
      });
      expect(out.length).toBe(PROMPT.length + maxNew);
    }
    void pipeline;
  });
});

// ── Adaptive cost-gate: "never materially slower than baseline". ─────────────
// These tests pin the THREE properties of the self-calibrating gate added to
// stop the prose/counting regression (paying a ~3.2x K-token verify to emit ONE
// token on a wrong draft) while keeping the repetitive win.

// A NON-repetitive oracle: the next token depends on absolute POSITION, so even
// when a suffix recurs the follower differs → n-gram drafts are rejected →
// acceptance stays ~0 → the gate must back off to cheap single-token rounds.
function nonRepetitiveNextToken(history: readonly number[]): number {
  const n = history.length;
  const a = history[n - 1] ?? 0;
  const b = history[n - 2] ?? 0;
  const c = history[n - 3] ?? 0;
  return (a * 5 + b * 3 + c * 2 + n * 7 + 1) % VOCAB_SIZE;
}

describe('Pipeline spec-decode adaptive cost-gate', () => {
  it('(a) backs off on a non-repetitive stream: drafted rounds stay LOW + lossless', async () => {
    const MAXN = 60;
    // Baseline reference uses the SAME oracle → lossless must hold regardless.
    const base = buildOracleStation([...PROMPT], nonRepetitiveNextToken);
    const baseline = await new Pipeline({
      stations: [base.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      disableNativeGenerate: true,
    }).generate({ promptTokens: new Uint32Array(PROMPT), maxNewTokens: MAXN });

    const spec = buildOracleStation([...PROMPT], nonRepetitiveNextToken);
    const out = await new Pipeline({
      stations: [spec.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      specDecode: true,
      specDecodeK: 4,
      specDecodeAdaptive: true,
    }).generate({ promptTokens: new Uint32Array(PROMPT), maxNewTokens: MAXN });

    // LOSSLESS: identical tokens to the baseline greedy loop.
    expect([...out]).toEqual([...baseline]);
    // The gate detects near-zero acceptance and coasts on cheap single-token
    // rounds: drafted (candidate-bearing) rounds must be a small fraction of the
    // ~MAXN rounds. Generous bound (probes + warmup), but far below "every round
    // drafts" — that is the regression this prevents.
    expect(spec.calls.verifyBatchDrafted).toBeLessThan(MAXN / 3);
  });

  it('(a-contrast) the adaptive gate drafts FAR less than the legacy path on the same non-repetitive stream', async () => {
    const MAXN = 60;
    const legacy = buildOracleStation([...PROMPT], nonRepetitiveNextToken);
    await new Pipeline({
      stations: [legacy.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      specDecode: true,
      specDecodeK: 4,
      specDecodeAdaptive: false, // legacy: draft on any match at fixed K (min-match N/A)
    }).generate({ promptTokens: new Uint32Array(PROMPT), maxNewTokens: MAXN });

    const adaptive = buildOracleStation([...PROMPT], nonRepetitiveNextToken);
    await new Pipeline({
      stations: [adaptive.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      specDecode: true,
      specDecodeK: 4,
      specDecodeAdaptive: true,
    }).generate({ promptTokens: new Uint32Array(PROMPT), maxNewTokens: MAXN });

    // Legacy drafts on every recurring suffix → many wasted K-token verifies.
    // The adaptive gate detects near-zero acceptance and coasts → far fewer
    // drafted rounds. This is the exact regression the gate removes.
    expect(adaptive.calls.verifyBatchDrafted).toBeLessThan(
      legacy.calls.verifyBatchDrafted,
    );
  });

  it('(b) on a highly repetitive stream it still drafts aggressively + lossless', async () => {
    const MAXN = 48;
    // The default oracle locks into a short repeating cycle → high acceptance.
    const base = buildOracleStation([...PROMPT]);
    const baseline = await new Pipeline({
      stations: [base.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      disableNativeGenerate: true,
    }).generate({ promptTokens: new Uint32Array(PROMPT), maxNewTokens: MAXN });

    const spec = buildOracleStation([...PROMPT]);
    const out = await new Pipeline({
      stations: [spec.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      specDecode: true,
      specDecodeK: 4,
      specDecodeAdaptive: true,
    }).generate({ promptTokens: new Uint32Array(PROMPT), maxNewTokens: MAXN });

    expect([...out]).toEqual([...baseline]);
    // High acceptance keeps the EWMA above break-even → keeps drafting, and
    // accepts multiple tokens per forward (so far fewer rounds than MAXN tokens).
    expect(spec.calls.verifyBatchDrafted).toBeGreaterThan(0);
    expect(spec.calls.verifyAcceptedTotal).toBeGreaterThan(0);
    expect(spec.calls.verifyBatch).toBeLessThan(MAXN); // multi-token-per-round
  });

  it('(c) cost-gate math: drafting is suppressed when EWMA acceptance < R-1', () => {
    // Re-derive the break-even the loop encodes, as a self-contained check of the
    // gate predicate `ewmaAccept > R - 1`. With R=3.2 the threshold E[a] is 2.2.
    const R = 3.2;
    const breakEven = R - 1;
    const gateAllowsDrafting = (ewmaAccept: number): boolean =>
      ewmaAccept > breakEven;

    // Below break-even → suppressed (the prose/counting case that regressed).
    expect(gateAllowsDrafting(0)).toBe(false); // accepted=0 (wrong drafts)
    expect(gateAllowsDrafting(2.0)).toBe(false);
    expect(gateAllowsDrafting(breakEven)).toBe(false); // strict >
    // Above break-even → drafting profitable (the repetitive win).
    expect(gateAllowsDrafting(2.5)).toBe(true);
    expect(gateAllowsDrafting(4)).toBe(true);

    // Per-token cost check: drafting wins iff tK/(a+1) < t1, i.e. a > R-1.
    const t1 = 76;
    const tK = 242; // K=4, live L4 mistral-7b
    expect(tK / t1).toBeCloseTo(R, 1);
    const perTokenDrafted = (a: number): number => tK / (a + 1);
    expect(perTokenDrafted(breakEven)).toBeCloseTo(t1, 0); // exactly break-even
    expect(perTokenDrafted(3)).toBeLessThan(t1); // a=3 > 2.2 → cheaper, draft
    expect(perTokenDrafted(1)).toBeGreaterThan(t1); // a=1 < 2.2 → costlier, skip
  });
});
